export interface ClaudeMessage {
  role: 'user' | 'assistant' | 'system';
  content: string;
  timestamp?: string;
}

export interface ClaudeConversation {
  sessionId: string;
  projectName: string;
  filePath: string;
  messages: ClaudeMessage[];
  title: string;
  gitBranch: string;
  messageCount: number;
  modifiedAt: Date;
  checksum?: string;
}

export interface JSONLEntry {
  type: 'user' | 'assistant' | 'tool_use' | 'tool_result' | 'system' | 'summary';
  message?: {
    role?: string;
    content?: string | ContentBlock[];
  };
  content?: string | ContentBlock[];
  timestamp?: string;
  sessionId?: string;
  cwd?: string;
  gitBranch?: string;
  summary?: string;
}

export interface ContentBlock {
  type: 'text' | 'tool_use' | 'tool_result';
  text?: string;
  name?: string;
  input?: Record<string, unknown>;
  output?: string;
}

export interface SyncOptions {
  apiUrl: string;
  apiKey: string;
  dryRun?: boolean;
  force?: boolean;
}

export interface SyncResult {
  success: boolean;
  conversationId?: string;
  slug?: string;
  url?: string;
  error?: string;
}

export interface Config {
  apiUrl: string;
  apiKey: string;
  lastSync?: string;
  syncedSessions?: string[];
}

export interface UploadPayload {
  title: string;
  slug?: string;
  description_user?: string;
  isPublic: boolean;
  tags: string[];
  checksum: string;
  source: 'claude';
}

