import { createHash } from 'node:crypto';
import type {
  ClaudeConversation,
  SyncResult,
} from '../types/index.js';

export class HowIClaudeCodeClient {
  private apiUrl: string;
  private apiKey: string;

  constructor(apiUrl: string, apiKey: string) {
    this.apiUrl = apiUrl.replace(/\/$/, ''); // Remove trailing slash
    this.apiKey = apiKey;
  }

  /**
   * Upload a conversation to How I Claude Code
   */
  async uploadConversation(
    conversation: ClaudeConversation,
    markdown: string,
    options: {
      title?: string;
      description?: string;
      tags?: string[];
      visibility?: 'private' | 'unlisted' | 'public';
      allowListing?: boolean;
    } = {}
  ): Promise<SyncResult> {
    try {
      // Calculate checksum from the JSON content (more stable than markdown)
      const conversationJson = JSON.stringify(conversation.messages);
      const checksum = this.calculateChecksum(conversationJson);

      // Create form data
      const formData = new FormData();

      // Create markdown blob
      const mdBlob = new Blob([markdown], { type: 'text/markdown' });
      const mdFilename = `${conversation.sessionId.slice(0, 8)}.md`;
      formData.append('file', mdBlob, mdFilename);

      // Add messages as JSON
      formData.append('messages_json', conversationJson);

      // Add metadata
      formData.append(
        'title',
        options.title || this.generateTitle(conversation)
      );
      formData.append('checksum', checksum);
      formData.append('source', 'claude');
      formData.append('visibility', options.visibility || 'private');
      formData.append('allowListing', String(options.allowListing ?? false));

      if (options.description) {
        formData.append('description_user', options.description);
      }

      if (options.tags && options.tags.length > 0) {
        formData.append('tags', JSON.stringify(options.tags));
      }

      // Upload to API
      const response = await fetch(`${this.apiUrl}/api/conversations`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
        },
        body: formData,
      });

      if (!response.ok) {
        const errorText = await response.text();
        let errorMessage = `Upload failed: ${response.status} ${response.statusText}`;

        try {
          const errorJson = JSON.parse(errorText);
          errorMessage = errorJson.error || errorMessage;
        } catch {
          // Use default error message
        }

        return {
          success: false,
          error: errorMessage,
        };
      }

      const result = (await response.json()) as {
        id?: string;
        slug?: string;
        url?: string;
      };

      return {
        success: true,
        conversationId: result.id,
        slug: result.slug,
        url: result.url,
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  }

  /**
   * Trigger processing for a conversation
   */
  async triggerProcessing(conversationId: string): Promise<boolean> {
    try {
      const response = await fetch(`${this.apiUrl}/api/ingest`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ conversationId }),
      });

      return response.ok;
    } catch {
      return false;
    }
  }

  /**
   * Test API connection
   */
  async testConnection(): Promise<boolean> {
    try {
      const response = await fetch(`${this.apiUrl}/api/health`, {
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
        },
      });

      return response.ok;
    } catch {
      return false;
    }
  }

  /**
   * Calculate SHA-256 checksum
   */
  private calculateChecksum(content: string): string {
    return createHash('sha256').update(content).digest('hex');
  }

  /**
   * Generate a title from conversation content
   */
  private generateTitle(conversation: ClaudeConversation): string {
    if (conversation.title && conversation.title !== 'Untitled Conversation') {
      return conversation.title;
    }

    const firstUserMessage = conversation.messages.find(
      (m) => m.role === 'user'
    );

    if (firstUserMessage) {
      // Take first 50 chars of first user message
      const title = firstUserMessage.content
        .slice(0, 50)
        .replace(/\s+/g, ' ')
        .trim();

      return title + (firstUserMessage.content.length > 50 ? '...' : '');
    }

    return `Conversation from ${conversation.projectName}`;
  }
}

