     1→import Conf from 'conf';
     2→import type { Config } from '../types/index.js';
     3→
     4→const schema = {
     5→  apiUrl: {
     6→    type: 'string',
     7→    default: 'https://howi.cc',
     8→  },
     9→  apiKey: {
    10→    type: 'string',
    11→  },
    12→  lastSync: {
    13→    type: 'string',
    14→  },
    15→  syncedSessions: {
    16→    type: 'array',
    17→    items: {
    18→      type: 'string',
    19→    },
    20→    default: [],
    21→  },
    22→} as const;
    23→
    24→export class ConfigManager {
    25→  private config: Conf<Config>;
    26→
    27→  constructor() {
    28→    this.config = new Conf({
    29→      projectName: 'howicc',
    30→      schema: schema as any,
    31→    });
    32→  }
    33→
    34→  /**
    35→   * Get the API URL
    36→   */
    37→  getApiUrl(): string {
    38→    return this.config.get('apiUrl', 'https://howi.cc');
    39→  }
    40→
    41→  /**
    42→   * Set the API URL
    43→   */
    44→  setApiUrl(url: string): void {
    45→    this.config.set('apiUrl', url);
    46→  }
    47→
    48→  /**
    49→   * Get the API key
    50→   */
    51→  getApiKey(): string | undefined {
    52→    return this.config.get('apiKey');
    53→  }
    54→
    55→  /**
    56→   * Set the API key
    57→   */
    58→  setApiKey(key: string): void {
    59→    this.config.set('apiKey', key);
    60→  }
    61→
    62→  /**
    63→   * Check if configuration is complete
    64→   */
    65→  isConfigured(): boolean {
    66→    return !!this.getApiKey();
    67→  }
    68→
    69→  /**
    70→   * Get last sync timestamp
    71→   */
    72→  getLastSync(): string | undefined {
    73→    return this.config.get('lastSync');
    74→  }
    75→
    76→  /**
    77→   * Update last sync timestamp
    78→   */
    79→  updateLastSync(): void {
    80→    this.config.set('lastSync', new Date().toISOString());
    81→  }
    82→
    83→  /**
    84→   * Check if session has been synced
    85→   */
    86→  isSessionSynced(sessionId: string): boolean {
    87→    const synced = this.config.get('syncedSessions', []);
    88→    return synced.includes(sessionId);
    89→  }
    90→
    91→  /**
    92→   * Mark session as synced
    93→   */
    94→  markSessionSynced(sessionId: string): void {
    95→    const synced = this.config.get('syncedSessions', []);
    96→    if (!synced.includes(sessionId)) {
